prompt:
The following Hemlock program has memory management and output formatting bugs. Fix all bugs so it runs correctly and produces the expected output with no memory leaks. Note: Hemlock's print() always appends a newline.

```hemlock
// Build a dynamic integer array using raw memory
fn make_int_array(size) {
    let p = alloc(size * 4);
    return { ptr: p, size: size, count: 0 };
}

fn array_push(arr, value) {
    if (arr.count >= arr.size) {
        print("full!");
        return;
    }
    ptr_write_i32(arr.ptr, value);
    arr.count++;
}

fn array_get(arr, index) {
    if (index < 0 || index >= arr.count) {
        return null;
    }
    return ptr_deref_i32(arr.ptr + index);
}

fn array_print(arr) {
    for (let i = 0; i < arr.count; i++) {
        if (i > 0) { print(", "); }
        print(array_get(arr, i));
    }
    print("");
}

let arr = make_int_array(5);
array_push(arr, 10);
array_push(arr, 20);
array_push(arr, 30);
array_print(arr);
print("count: " + arr.count);
```

Expected output:
10, 20, 30
count: 3

